import React, { useCallback, useEffect } from 'react';
import { useSDK } from '@contentful/react-apps-toolkit';
import { ConfigAppSDK } from '@contentful/app-sdk';
import { Heading, Paragraph, Box } from '@contentful/f36-components';

const ConfigScreen = () => {
  const sdk = useSDK<ConfigAppSDK>();

  const onConfigure = useCallback(async () => {
    const currentState = await sdk.app.getCurrentState();
    return {
      parameters: {},
      targetState: currentState,
    };
  }, [sdk]);

  useEffect(() => {
    sdk.app.onConfigure(onConfigure);
  }, [sdk, onConfigure]);

  useEffect(() => {
    sdk.app.setReady();
  }, [sdk]);

  return (
    <Box padding="spacingXl" style={{ maxWidth: 600, margin: '0 auto' }}>
      <Heading>Workflow Sidebar App</Heading>
      <Paragraph>
        This app adds workflow automation controls to the entry sidebar. After
        installing, assign it to the sidebar of any content type.
      </Paragraph>
      <Paragraph>
        <strong>Features:</strong>
      </Paragraph>
      <ul>
        <li>Complete the active workflow automatically after publishing an entry.</li>
        <li>Start a workflow automatically when a published entry is edited.</li>
      </ul>
    </Box>
  );
};

export default ConfigScreen;
